import numpy as np
def resumen(x):
    x = np.asarray(x, dtype=float)
    return {"n": int(x.size), "mean": round(float(np.mean(x)), 4), "median": round(float(np.median(x)), 4), "std": round(float(np.std(x, ddof=1)), 4)}
print(resumen([1, 2, 3, 4, 5]))

def max_bias(pob, counts):
    total = sum(counts.values())
    return max(abs(counts[k] / total - pob[k]) for k in pob)
print(max_bias({"Lima": 0.5, "Cusco": 0.5}, {"Lima": 9, "Cusco": 1}))

